import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"173. Rosters","description":"","frontmatter":{"title":"173. Rosters","eba":"Mental Health Services 2024-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/173-rosters.md","filePath":"ebas/mental-health/support-services/preliminary/173-rosters.md"}'),a={name:"ebas/mental-health/support-services/preliminary/173-rosters.md"};function n(i,e,l,h,p,c){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_173-rosters" tabindex="-1">173. Rosters <a class="header-anchor" href="#_173-rosters" aria-label="Permalink to &quot;173. Rosters&quot;">​</a></h1><p><strong>173.1</strong> A roster of at least 28 days’ duration shall be posted at least 28 days before it comes into operation at each work location in a place where it may be readily seen by such Employees and the Secretary or other accredited representative of HACSU.</p><p><strong>173.2</strong> This 28-day roster provision will operate from the next roster cycle commencing 3 months after the commencement of this Agreement</p><p><strong>173.3</strong> Roster Requirements</p><p><strong>(a)</strong> Rosters will set out:</p><p><strong>(i)</strong> the Employees’ daily ordinary working hours</p><p><strong>(ii)</strong> Starting and finishing time</p><p><strong>(iii)</strong> Meal intervals.</p><p><strong>(b)</strong> Provide an Employee who works 0.8 EFT or more with two consecutive days off per week. Nothing in this subclause (b) is intended to:</p><p><strong>(i)</strong> restrict an Employee requesting single days off, including as a self- rostering request; or</p><p><strong>(ii)</strong> prevent an Employee who works 0.8 EFT or more from having a single day off rostered where they also have consecutive days off rostered that week.</p><p><strong>(c)</strong> From the commencement of the Agreement, an Employer may use an alternative method to record meal interval allocations outlined in 173.3(a)(iii) if the electronic roster system being used is unable to accommodate its inclusion. This will be located in each work location where it can be readily accessible seen by such Employees and/or other representatives of the Union(s) to ensure compliance with meal break provisions, for a period of no less than 6 years.</p><p><strong>(d)</strong> Where an Employee works a set Monday to Friday arrangement of hours without change, then no roster is required to be established.</p><p><strong>173.4</strong> Change of roster</p><p><strong>(a)</strong> Where the Employer requires an Employee, without seven (7) days’ notice and outside the expected circumstances in clause 173.4 above, to perform ordinary duty at other times than those previously rostered, the Employee shall be paid in accordance with the hours worked plus a daily change of roster allowance pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>[<a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>] (as it applies to Support Services Employees).</p><p><strong>(b)</strong> Provided that a part-time Employee who agrees to work shift(s) in addition to those already rostered will not be entitled to the Change of Roster allowance for the additional shift(s) worked.</p><p><strong>(c)</strong> The Change of Roster allowance in clause 173.4 is calculated at a rate of 2.5% of the weekly wage rate payable for the “Patient Services Assistant Level 2” classification pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>[<a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>].</p><p><strong>173.5</strong> An Employee may apply in writing to the Employer to have their roster fixed by the provisions of clause 173.6 below in lieu of clauses 173.1 to 173.4 above.</p><p><strong>173.6</strong> Rosters shall be fixed by mutual agreement, subject to the provisions of this Part.</p><p><strong>173.7</strong> An Employee may repudiate a request made under clause 173.5 at any time, by giving written notice to the Employer. In such a case the roster of the Employee shall be determined according to clauses 173.1 to 173.4 from the commencement of the next full roster period, being not less than five (5) clear days after such repudiation is received in writing by the Employer.</p><p><strong>173.8</strong> Rosters will be drawn up so as to provide at least eight (8) hours between successive periods of ordinary duty.</p><p><strong>173.9</strong> Rosters which include work on public holiday</p><p><strong>(a)</strong> Employers must implement a policy or procedure for the issuance and finalisation of rosters which cover the performance of work on a public holiday under the Act.</p><p><strong>(b)</strong> The policy / procedure referenced at subclause 173.9(a) above should:</p><p><strong>(i)</strong> set out the process for an Employee to request not to work on a public holiday they are requested to work; and</p><p><strong>(ii)</strong> set out the process for the Employer to provide a written response to an Employee&#39;s request not to work on a public holiday they are requested to work</p><p><strong>(c)</strong> An Employer who receives a request under subclause 173.9(b) 94.9(b)(i) must accept that request unless the Employer determines that the refusal is not reasonable in the circumstances. The factors an Employer must consider when determining whether a request is not reasonable include:</p><p><strong>(i)</strong> whether the Employee has clearly explained a reason for refusing to work on the relevant public holiday</p><p><strong>(ii)</strong> the nature of the Employers’ workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee</p><p><strong>(iii)</strong> the capacity for the Employer to find a replacement Employee to perform the same work</p><p><strong>(iv)</strong> the Employee’s personal circumstances (including family responsibilities) to the extent that those circumstances have been disclosed to the Employer</p><p><strong>(v)</strong> whether the Employee could reasonably have expected the Employer to request that they work on the public holiday(s)</p><p><strong>(vi)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects expectation of, work on the public holiday(s)</p><p><strong>(vii)</strong> the type of employment of the Employee (e.g. whether full-time, part- time, casual or shiftwork)</p><p><strong>(viii)</strong> the amount of notice in advance of the public holiday given by the Employer when making the request</p><p><strong>(ix)</strong> the amount of notice in advance of the public holiday given by the Employee when refusing the request</p><p><strong>(x)</strong> the number of public holidays the Employee has previously worked and been required to work in recent roster durations; and</p><p><strong>(xi)</strong> any other relevant matter.</p><p><strong>(d)</strong> Where the Employer has requested an Employee to work any public holiday(s) and either:</p><p><strong>(i)</strong> the Employee has not made a request not to work the public holiday in accordance with the policy or procedure referenced at subclause 173.9(b) above; or</p><p><strong>(ii)</strong> the Employer has determined that a request was not reasonable (taking into account the factors in subclause 173.9(c), the Employer may require the Employee to work on the relevant public holiday(s).</p><p>Plain language terms: rostering, shift roster, duty roster, roster changes.</p>',42)])])}const m=t(a,[["render",n]]);export{u as __pageData,m as default};
